#!/bin/sh
# Name: Zen MTP
# Author: Anthony Gress
# Icon: data:image/png;base64,
# Created: 2026-05-14
# Version: 1.1
# Description: Switches Kindle to MTP mode for file transfer

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
SPLASH="$SCRIPT_DIR/zen.png"

# Double clear + sleep to flush framebuffer before framework can repaint covers.
force_refresh() {
    eips -c > /dev/null 2>&1
    eips -c > /dev/null 2>&1
    sleep 1
}

force_refresh

# Show splash PNG if present, else fall back to text.
if command -v eips >/dev/null 2>&1; then
    if [ -f "$SPLASH" ]; then
        eips -g "$SPLASH" > /dev/null 2>&1
    else
        eips 0 0 "Zen MTP" > /dev/null 2>&1
        eips 0 2 "Enabling MTP mode..." > /dev/null 2>&1
    fi
fi

for JOB in usbnetlite usbnetd usbnet-autostart usbnetwork usbnet; do
    stop "$JOB" >/dev/null 2>/dev/null || true
done
rm -f /mnt/us/usbnet/auto 2>/dev/null || true

GDIR="/sys/kernel/config/usb_gadget/mtpgadget"
UDC_HW=$(ls /sys/class/udc/ 2>/dev/null | head -1)

echo "" > "$GDIR/UDC" 2>/dev/null || true

stop mtp >/dev/null 2>/dev/null || true
sleep 1
start mtp >/dev/null 2>/dev/null

sleep 3

CURR=$(cat "$GDIR/UDC" 2>/dev/null)
if [ -z "$CURR" ] && [ -n "$UDC_HW" ]; then
    echo "$UDC_HW" > "$GDIR/UDC" 2>/dev/null || true
fi

sleep 2
